{"file_path": "/tmp/TestNpeFix.kt", "content": "import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.CodeStyleEditorConfigProperty
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EditorConfigProperty
import com.pinterest.ktlint.rule.engine.core.api.editorconfig.EndOfLineProperty
import com.pinterest.ktlint.ruleset.standard.rules.NoConsecutiveBlankLinesRule

fun main() {
    val code = """
sealed class Hello



""".trimIndent()

    println("Testing NPE fix for consecutive blank lines at end of file with class without body...")
    println("Code to test:")
    println(code)
    println("---")

    val ruleEngine = KtLintRuleEngine(
        ruleProviders = setOf { NoConsecutiveBlankLinesRule() }
    )

    try {
        val lintErrors = ruleEngine.lint(Code.fromSnippet(code))
        println("SUCCESS! No NPE thrown.")
        println("Lint errors found: ${lintErrors.count()}")
        lintErrors.forEach { error ->
            println("  - Line ${error.line}, Col ${error.col}: ${error.detail}")
        }
    } catch (e: Exception) {
        println("FAILED with exception: ${e.message}")
        e.printStackTrace()
    }
}
"}

